        std.fmt.bufPrint(&buf, "{d} {s}",.{ scaled_value, selected_unit }) orelse unreachable;

    // Wait, std.fmt.bufPrint with {d} on a float might produce 3.3 or 33.
    // Let's refine the formatting to match the expected output exactly.
